#include <bits/stdc++.h>
using namespace std;
using vi = vector<int>;
using vvi = vector<vi>;
const int mod = 1e9 + 7;
int main()
{
    int t;
    cin>>t;

    while (t--){
        int n,m;
        cin>>m>>n;//m is the number of dishes and n is the number of cooks

        vi x(n + 1),y(n + 1);
        vvi dp(n + 1,vi(m + 1));

        for (int i = 1;i<=n;i++)
            cin>>x[i]>>y[i];

        dp[0][0] = 1;//base case

        for (int i = 1;i<=n;i++)
            for (int j = 0;j<=m;j++)
                //dp[i][j] is number of ways of giving j dishes to first i cooks
                for (int k = x[i];k<=y[i];k++)
                    if (j >= k)//k = number of dishes given to ith cook
                        dp[i][j] = (dp[i][j] + (dp[i - 1][j - k]))%mod;

        cout<<(dp[n][m]%mod + mod)%mod<<endl;

        //dp[n][m] == (dp[n][m]%mod + mod)%mod 
    }
    return 0;
}

