#include <stdio.h>

#define MAX_N 100 // Maximum number of cooks
#define MAX_M 1000 // Maximum number of dishes
#define MOD 1000000007

int main() {
    int t;
    scanf("%d", & t);

    while (t--) {
        int n, m;
        scanf("%d %d", & m, & n); // m is the number of dishes and n is the number of cooks

        int x[MAX_N + 1], y[MAX_N + 1];
        long long dp[MAX_N + 1][MAX_M + 1] = {
            0
        }; // Using long long to prevent overflow

        for (int i = 1; i <= n; i++) {
            scanf("%d %d", & x[i], & y[i]);
        }

        dp[0][0] = 1; // base case

        for (int i = 1; i <= n; i++) {
            for (int j = 0; j <= m; j++) {
                // dp[i][j] is the number of ways of giving j dishes to the first i cooks
                for (int k = x[i]; k <= y[i]; k++) {
                    if (j >= k) { // k = number of dishes given to ith cook
                        dp[i][j] = (dp[i][j] + dp[i - 1][j - k]) % MOD;
                    }
                }
            }
        }

        printf("%lld\n", (dp[n][m] + MOD) % MOD); // Ensure non-negative output
    }
    return 0;
}

