import java.util.*;
import java.lang.*;
import java.io.*;

class Codechef {
    public static void main(String[] args) throws java.lang.Exception {
        // Initialize scanner for input
        Scanner sc = new Scanner(System.in);

        int t = sc.nextInt(); // Read number of test cases

        while (t-- > 0) {
            int m = sc.nextInt(); // Number of dishes
            int n = sc.nextInt(); // Number of cooks

            int[] x = new int[n + 1];
            int[] y = new int[n + 1];
            long[][] dp = new long[n + 1][m + 1];

            // Read the minimum and maximum dishes for each cook
            for (int i = 1; i <= n; i++) {
                x[i] = sc.nextInt();
                y[i] = sc.nextInt();
            }

            dp[0][0] = 1; // Base case

            // Fill the dp array
            for (int i = 1; i <= n; i++) {
                for (int j = 0; j <= m; j++) {
                    // dp[i][j] is number of ways of giving j dishes to first i cooks
                    for (int k = x[i]; k <= y[i]; k++) {
                        if (j >= k) {
                            dp[i][j] = (dp[i][j] + dp[i - 1][j - k]) % 1000000007; // mod
                        }
                    }
                }
            }

            // Output the result for the current test case
            System.out.println((dp[n][m] + 1000000007) % 1000000007);
        }

        // Close the scanner
        sc.close();
    }
}
